  ('dietitian-moex-02423', 'dietitian', 'dietitian-moex-106-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '人類因攝食烹煮未熟的豬肉內之包囊蟲而感染寄生蟲，此包囊蟲是下列何種寄生蟲的幼蟲？', '["肝吸蟲", "有鉤絛蟲", "旋毛蟲", "鈎蟲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "a2d427b73b25", "answer_pdf_sha1": "ba57cc36403b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02424', 'dietitian', 'dietitian-moex-106-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者是人體腸道內最大型的寄生性圓蟲？', '["蛔蟲", "蟯蟲", "吸蟲", "絛蟲"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "a2d427b73b25", "answer_pdf_sha1": "ba57cc36403b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
