  ('dietitian-moex-02428', 'dietitian', 'dietitian-moex-106-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關以紫外線進行餐飲器具及設備殺菌的敘述，下列何者正確？', '["利用波長340～380 nm的紫外線，其中以365 nm的殺菌力最強", "僅能作容器、刀、砧板的表面殺菌", "無法殺滅調理場所內空氣與水中的微生物", "不受障礙物與吸收物質所影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "a2d427b73b25", "answer_pdf_sha1": "ba57cc36403b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02429', 'dietitian', 'dietitian-moex-106-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據包裝食品含基因改造食品原料標示應遵行事項之規定，下列敘述何者正確？', '["非基因改造或含非基因改造之標示字體大小不予規範", "包裝食品所含非基因改造食品原料，其在國際上如未存在已審核通過可種植之基因改造作物，或作為 食品原料使用並未存在有基因改造者，仍得標示非基因改造或不是基因改造字樣", "標示基因改造、含基因改造之字體須與其他文字明顯區別，字體長度及寬度不得小於二厘米", "醬油等包裝食品若直接使用基因改造食品原料，於終產品已不含轉殖基因片段或轉殖蛋白質者，不須 標示為基因改造"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "a2d427b73b25", "answer_pdf_sha1": "ba57cc36403b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02430', 'dietitian', 'dietitian-moex-106-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '市售之食品含有下列那些內容物時，應於其容器或外包裝上，顯著標示含有致過敏性內容物名稱之醒語', '["堅果種子類", "蝦及其製品", "芒果及其製品", "花生及其製品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "a2d427b73b25", "answer_pdf_sha1": "ba57cc36403b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02431', 'dietitian', 'dietitian-moex-106-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關農藥之敘述，下列何者錯誤？', '["安殺番因列為持久性有機污染物，所以被各國禁用", "農民應依農藥標示之使用方法使用農藥", "蘇力菌可用來作為殺菌的生物製劑，對人體無害", "有機磷劑是最常用的殺蟲劑，可抑制乙醯膽鹼酯酶的活性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:58+00:00", "source_pdf_sha1": "a2d427b73b25", "answer_pdf_sha1": "ba57cc36403b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "103", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
